  ?participantStatement pq:P5049 ?wins .
  ?participantStatement pq:P5050 ?losses .
}

SELECT(COUNT(?game) AS ?total) WHERE {
  VALUES ?series {
    wd:Q56692089 wd:Q14870260 wd:Q3511178
  }
  ?series wdt:P580 ?seriesStart ; wdt:P582 ?seriesEnd .
  ?game wdt:P31 wd:Q200199 ; wdt:P276 wd:Q49136 ; wdt:P585 ?gameTime .
  FILTER(?gameTime >= ?seriesStart && ?gameTime <= ?seriesEnd)
}

SELECT(COUNT(DISTINCT ?game) AS ?count) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?game wdt:P361 ?series .
  ?game wdt:P276 wd:Q49136 .
}

SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  ?game wdt:P361 wd:Q122932436 ; wdt:P1586 ?attendance .
}

SELECT(SUM(xsd:integer(?gamesAmount)) AS ?totalGames) WHERE {
  ?edition wdt:P179 wd:Q1363275 .
  {
    ?edition wdt:P1345 wd:Q650840 ; wdt:P1346 wd:Q334634 ; p:P482 / psv:P482 ?gamesNode .
  } UNION {
    ?edition wdt:P1345 wd:Q334634 ; wdt:P1346 wd:Q650840 ; p:P482 / psv:P482 ?gamesNode .
  }
  ?gamesNode wikibase:quantityAmount ?gamesAmount .
}

SELECT(SUM(?games) AS ?total) WHERE {
  {
    ?series wdt:P361 wd:Q186453 .
    ?series wdt:P580 ?start .
    FILTER(YEAR(?start) = 1975)
    ?series wdt:P2041 ?games .
  } UNION {
    ?series wdt:P361 wd:Q186453 .
    ?series wdt:P580 ?start .
    FILTER(YEAR(?start) = 2013)
    ?series wdt:P2041 ?games .
  } UNION {
    ?series wdt:P361 wd:Q728810 .
    ?series wdt:P580 ?start .
    FILTER(YEAR(?start) = 2018)
    ?series wdt:P2041 ?games .
  }
}

SELECT(MAX(?races) AS ?maxRaces) WHERE {
  ?season wdt:P31 wd:Q27532865 .
  ?season wdt:P3450 wd:Q9673 .
  ?season wdt:P2414 wd:Q172721 .
  ?season wdt:P1798 ?races .
}

SELECT((COALESCE(?stKildaCount , 0) + COALESCE(?essendonCount , 0) + COALESCE(?richmondCount , 0)) - COALESCE(?collingwoodCount , 0) AS ?difference) WHERE {
  {
    SELECT(COUNT(*) AS ?stKildaCount) WHERE {
      ?season wdt:P1346 wd:Q1084121 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?essendonCount) WHERE {
      ?season wdt:P1346 wd:Q251090 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?richmondCount) WHERE {
      ?season wdt:P1346 wd:Q2521385 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
  {
    SELECT(COUNT(*) AS ?collingwoodCount) WHERE {
      ?season wdt:P1346 wd:Q249679 .
      ?season wdt:P31 / wdt:P279 * wd:Q19840852 .
    }
  }
}

SELECT((MAX(?count) - MIN(?count)) AS ?difference) WHERE {
  {
    SELECT ?year(COUNT(*) AS ?count) WHERE {
      ?race wdt:P31 wd:Q129237 .
      ?race p:P1346 ?statement .
      ?statement ps:P1346 wd:Q9673 .
      ?statement pq:P54 wd:Q25761776 .
      ?race wdt:P585 ?date .
      BIND(xsd:integer(SUBSTR(STR(?date) , 1 , 4)) AS ?year)
      FILTER(?year > 2015)
    }
    GROUP BY ?year
  }
}

SELECT(SUM(?dodgersWins) AS ?totalWins) WHERE {
  VALUES ?series {
    wd:Q1004352 wd:Q1004228 wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P1346 ?winner ; wdt:P5504 ?games .
  BIND(IF(?series IN(wd:Q1004352 , wd:Q1004228) , 3 , 4) AS ?requiredWins)
  BIND(IF(?winner = wd:Q334634 , ?requiredWins , ?games - ?requiredWins) AS ?dodgersWins)
}

SELECT(SUM(?games) AS ?total_games) WHERE {
  VALUES ?series {
    wd:Q3511262 wd:Q3511261
  }
  ?series wdt:P1350 ?games .
}

SELECT(SUM(?count) AS ?totalRunnersUp) WHERE {
  {
    SELECT ?club(COUNT(?event) AS ?count) WHERE {
      VALUES ?club {
        wd:Q2521385 wd:Q249679
      }
      ?event wdt:P31 wd:Q3006481 ; wdt:P710 ?club ; wdt:P1346 ?winner .
      FILTER(?club != ?winner)
    }
    GROUP BY ?club
  }
}

SELECT((?games2013 - ?games1975) AS ?difference) WHERE {
  wd:Q14870260 wdt:P1350 ?games2013 .
  wd:Q3511178 wdt:P1350 ?games1975 .
}

SELECT(SUM(?games) AS ?totalGames) WHERE {
  VALUES ?seriesType {
    wd:Q300972 wd:Q20206337
  }
  ?edition wdt:P31 ?seriesType ; wdt:P1346 ?winnerSeason ; wdt:P582 ?endDate ; wdt:P1350 ?games .
  ?winnerSeason wdt:P54 wd:Q504309 .
  FILTER(xsd:date(?endDate) >= "1985-10-16" ^^ xsd:date)
}

SELECT(MIN(YEAR(?collDate)) AS ?firstCollYear) WHERE {
  VALUES ?collLeague {
    wd:Q2352741 wd:Q50783
  }
  ?collSeason wdt:P118 ?collLeague ; wdt:P1346 wd:Q249679 ; wdt:P585 ?collDate .
}

SELECT(COUNT(DISTINCT ?driver) AS ?count) WHERE {
  {
    ?team2002 wdt:P1344 wd:Q69844 .
    ?team2002 wdt:P57 ?driver .
  } UNION {
    ?team2003 wdt:P1344 wd:Q69859 .
    ?team2003 p:P57 ?stmt .
    ?stmt ps:P57 ?driver .
    ?stmt pq:P3831 wd:Q104121 .
  }
}

SELECT(COUNT(?game) AS ?count) WHERE {
  VALUES ?series {
    wd:Q3511178 wd:Q14870260 wd:Q56692089
  }
  ?game wdt:P361 ?series .
  ?game wdt:P276 wd:Q49136 .
}

SELECT(MIN(?games) AS ?minGames) WHERE {
  VALUES ?year_str {
    "1975" "1986" "2004" "2007" "2013" "2018"
  }
  ?series wdt:P31 wd:Q1529013 ; wdt:P1346 wd:Q213959 ; wdt:P585 ?date ; wdt:P1350 ?games .
  FILTER(SUBSTR(STR(?date) , 1 , 4) = ?year_str)
}

SELECT ?difference WHERE {
  VALUES ?series_2008 {
    wd:Q3511262
  }
  VALUES ?series_1977 {
    wd:Q1004352
  }
  ?series_2008 wdt:P1350 ?games_2008 .
  ?series_1977 wdt:P1350 ?games_1977 .
  BIND(?games_2008 - ?games_1977 AS ?difference)
}

SELECT(SUM(?numRaces) AS ?total) WHERE {
  {
    SELECT ?season WHERE {
      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY ASC(?time)
    LIMIT 1
  } UNION {
    SELECT ?season WHERE {
      ?season wdt:P31 wd:Q171879 ; wdt:P1346 wd:Q9671 ; wdt:P585 ?time .
    }
    ORDER BY DESC(?time)
    LIMIT 1
  }
  ?season wdt:P1113 ?numRaces .
}

SELECT(SUM(xsd:integer(?wins)) AS ?total_games) WHERE {
  ?series wdt:P31 wd:Q1363275 ; wdt:P1923 wd:Q334634 ; wdt:P1923 wd:Q650840 ; wdt:P585 ?date .
  {
    ?series p:P1366 / ps:P1366 ?team ; p:P1366 / pq:P1267 ?wins .
  } UNION {
    ?series p:P1367 / ps:P1367 ?team ; p:P1367 / pq:P1267 ?wins .
  }
  VALUES ?team {
    wd:Q334634 wd:Q650840
  }
  BIND(xsd:integer(SUBSTR(STR(?date) , 1 , 4)) AS ?year)
  FILTER(?year >= 1978 && ?year <= 2009)
}

SELECT((MAX(YEAR(?date)) - MIN(YEAR(?date))) AS ?difference) WHERE {
  {
    ?edition wdt:P1346 wd:Q334634 ; wdt:P1344 wd:Q650840 ; wdt:P585 ?date
  } UNION {
    ?edition wdt:P1346 wd:Q650840 ; wdt:P1344 wd:Q334634 ; wdt:P585 ?date
  }
}

SELECT(COUNT(?race) AS ?count) WHERE {
  ?race wdt:P31 wd:Q7965 ; wdt:P585 ?date ; wdt:P3764 wd:Q9673 .
  FILTER(YEAR(?date) >= 2016)
}
